class Solution {
    public int findCheapestPrice(int n, int[][] flights, int src, int dst, int K) {
        int[] dist = new int[n];
        Arrays.fill(dist, Integer.MAX_VALUE / 2);
        dist[src] = 0;
        for (int i = 0; i <= K; i++) {
            int[] next = dist.clone();
            for (int[] f : flights) {
                int u = f[0], v = f[1], w = f[2];
                if (dist[u] != Integer.MAX_VALUE / 2) {
                    next[v] = Math.min(next[v], dist[u] + w);
                }
            }
            dist = next;
        }
        return dist[dst] >= Integer.MAX_VALUE / 2 ? -1 : dist[dst];
    }
}

class Solution {
    public int findCheapestPrice(int n, int[][] flights, int src, int dst, int K) {
        int[][] graph = new int[n][n];
        for (int[] f : flights) graph[f[0]][f[1]] = f[2];
        PriorityQueue<int[]> pq = new PriorityQueue<>((a, b) -> a[0] - b[0]);
        pq.add(new int[]{0, src, 0}); // cost, city, stops
        int[] dist = new int[n];
        Arrays.fill(dist, Integer.MAX_VALUE);
        dist[src] = 0;
        while (!pq.isEmpty()) {
            int[] curr = pq.poll();
            int cost = curr[0], city = curr[1], stops = curr[2];
            if (city == dst) return cost;
            if (stops > K) continue;
            for (int nei = 0; nei < n; nei++) {
                if (graph[city][nei] > 0) {
                    int newCost = cost + graph[city][nei];
                    if (newCost < dist[nei]) {
                        dist[nei] = newCost;
                        pq.add(new int[]{newCost, nei, stops + 1});
                    }
                }
            }
        }
        return -1;
    }
}
